using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF Core 9: default discriminator renamed from "Discriminator" to "$type".
            // Preserve old name so existing documents and raw SQL
            // (e.g. SELECT * FROM c WHERE c.Discriminator = 'Blog') keep working.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9: id no longer includes discriminator prefix.
            // Preserve "Blog|1" format so existing documents remain accessible.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex — EF Core 9 Cosmos provider now throws on HasIndex.
        // Cosmos DB indexing is managed via the container's indexing policy
        // (Azure Portal, Bicep, or Terraform), not through EF Core.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

